def normalize_name(s: str) -> str:
    return " ".join(s.strip().split())
print(normalize_name("  Ana   Quispe "))
print(normalize_name(normalize_name("  Ana   Quispe ")))

def parse_edad(txt: str):
    try:
        return int(txt.strip())
    except ValueError as e:
        raise ValueError(f"edad invalida: {txt!r}") from e
print(parse_edad(" 19 "))
try:
    parse_edad("x")
except ValueError as e:
    print(type(e).__name__, e)

