    return a + b
print(add(2, 3))

def report(*, title, n_rows):
    return f"{title}: {n_rows} filas"
print(report(title="intake", n_rows=3))

def clamp(x, lo=0, hi=100):
    if x < lo:
        return lo
    if x > hi:
        return hi
    return x
print(clamp(-5), clamp(50), clamp(200))

def summarize(nums):
    return {"n": len(nums), "total": sum(nums)}
print(summarize([1, 2, 3]))

def apply_all(fn, values):
    return [fn(v) for v in values]
print(apply_all(lambda x: x * 2, [1, 2, 3]))

def pipeline(x, steps):
    for step in steps:
        x = step(x)
    return x
print(pipeline("  Ana  ", [str.strip, str.upper]))

def outer(msg):
    def inner():
        return msg
    return inner
print(outer("hola")())

def safe_div(a, b):
    if b == 0:
        return None
    return a / b
print(safe_div(10, 2), safe_div(1, 0))

def validate_score(s):
    if not isinstance(s, (int, float)):
        return {"ok": False, "error": "type"}
    if not 0 <= s <= 100:
        return {"ok": False, "error": "range"}
    return {"ok": True, "value": s}
print(validate_score(80), validate_score(-1), validate_score("x"))

def decompose_intake(raw: dict):
    errors = []
    clean = {}
    for k, v in raw.items():
        if v is None or (isinstance(v, str) and not v.strip()):
            errors.append(k)
        else:
            clean[k] = v.strip() if isinstance(v, str) else v
    return clean, errors
print(decompose_intake({"nombres": " Ana ", "edad": ""}))

def total_lineas(montos):
    t = 0
    for m in montos:
        t += m
    return t
print(total_lineas([10, 20, 5]))

def mean(xs):
    if not xs:
        return None
    return sum(xs) / len(xs)
print(mean([2, 4, 6]), mean([]))

def reject_rate(statuses):
    n = len(statuses)
    if n == 0:
        return None
    return sum(1 for s in statuses if s == "reject") / n
print(reject_rate(["accept", "reject"]), reject_rate([]))

