def document_contract(fn):
    return {
        "name": fn.__name__,
        "doc": (fn.__doc__ or "").strip(),
    }
def parse_monto(s: str) -> str:
    """Normaliza monto textual strip."""
    return s.strip()
print(document_contract(parse_monto))
